#include<bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) meke_pair(x,y);
#define inf 0x3f3f3f3f
using namespace std;
inline int read(){
    int x=0,f=1;
    char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    while(ch>='0'&&ch<='9')x=x*10+ch-'0',ch=getchar();
    return x*f;
}
void write(int x){
    if(x<0)putchar('-'),x=-x;
    if(x>9)write(x/10);
    putchar(x%10+'0');return;
}
CI MAXN=5e3+5;
bool f[MAXN][MAXN];
int n,ans;
string s;
int main(void){
	//freopen("P1775.in","r",stdin);
	//freopen("P1775.out","w",stdout);
	//input
	cin>>s;
	s=' '+s;
	n=s.size()-1;
    for(int i=1;i<=n;++i)
    {
        f[i][i]=0;
        f[i][i+1]=(s[i]>s[i+1]);
    }
    //interval DP
    for(int len=2;len<=n;++len)//lenght
    {
        for(int l=1;l<=n-len+1;++l)//left
        {
            int r=l+len-1;//right
            if(s[l]==s[r])f[l][r]=f[l+1][r-1];
			else if(s[l]>s[r])f[l][r]=1;
            ans+=f[l][r];
        }
    }
    //print
    write(ans);
	return false;
}
